int parse_vm_config(const char* config_line, struct vm_hardware_config* hw_config) {
    // Validate input parameters
    if (config_line == NULL || *config_line == '\0' || hw_config == NULL) {
        return -1;
    }

    // Create a temporary copy of the configuration line to avoid modifying the original
    size_t line_len = strlen(config_line);
    char* temp_line = (char*)malloc(line_len + 1);
    if (temp_line == NULL) {
        return -1;
    }
    strcpy(temp_line, config_line);

    // Flags to track which configuration fields have been successfully parsed
    enum {
        FLAG_CPU = 1 << 0,
        FLAG_MEM = 1 << 1,
        FLAG_DISK = 1 << 2,
        FLAG_NET = 1 << 3
    };
    int fields_set = 0;

    char* current = temp_line;
    while (*current != '\0') {
        // Find the next comma delimiter
        char* comma = strchr(current, ',');
        size_t token_len;

        // Calculate length of current token
        if (comma != NULL) {
            token_len = comma - current;
        } else {
            token_len = strlen(current);
        }

        // Reject empty tokens (leading/trailing commas or consecutive commas)
        if (token_len == 0) {
            free(temp_line);
            return -1;
        }

        // Temporarily null-terminate the token for processing
        char saved_char = '\0';
        if (comma != NULL) {
            saved_char = *comma;
            *comma = '\0';
        }

        // Process the current token (key-value pair)
        char* token = current;
        char* eq_pos = strchr(token, '=');

        // Reject tokens without '=', empty key, or empty value
        if (eq_pos == NULL || eq_pos == token || *(eq_pos + 1) == '\0') {
            if (comma != NULL) {
                *comma = saved_char;
            }
            free(temp_line);
            return -1;
        }

        // Split token into key and value
        *eq_pos = '\0';
        const char* key = token;
        const char* value = eq_pos + 1;

        // Process each known configuration key
        if (strcmp(key, "cpu_model") == 0) {
            size_t val_len = strlen(value);
            if (val_len >= sizeof(hw_config->cpu_model)) {
                free(temp_line);
                return -1;
            }
            strncpy(hw_config->cpu_model, value, sizeof(hw_config->cpu_model) - 1);
            hw_config->cpu_model[sizeof(hw_config->cpu_model) - 1] = '\0';
            fields_set |= FLAG_CPU;
        } else if (strcmp(key, "memory_mb") == 0) {
            char* endptr;
            long mem_val = strtol(value, &endptr, 10);

            // Validate integer conversion: entire string is a valid positive integer within int range
            if (endptr != value + strlen(value) || mem_val < 0 || mem_val > INT_MAX) {
                free(temp_line);
                return -1;
            }
            hw_config->memory_mb = (int)mem_val;
            fields_set |= FLAG_MEM;
        } else if (strcmp(key, "disk_path") == 0) {
            size_t val_len = strlen(value);
            if (val_len >= sizeof(hw_config->disk_path)) {
                free(temp_line);
                return -1;
            }
            strncpy(hw_config->disk_path, value, sizeof(hw_config->disk_path) - 1);
            hw_config->disk_path[sizeof(hw_config->disk_path) - 1] = '\0';
            fields_set |= FLAG_DISK;
        } else if (strcmp(key, "network_adapter") == 0) {
            size_t val_len = strlen(value);
            if (val_len >= sizeof(hw_config->network_adapter)) {
                free(temp_line);
                return -1;
            }
            strncpy(hw_config->network_adapter, value, sizeof(hw_config->network_adapter) - 1);
            hw_config->network_adapter[sizeof(hw_config->network_adapter) - 1] = '\0';
            fields_set |= FLAG_NET;
        } else {
            // Reject unknown configuration keys
            if (comma != NULL) {
                *comma = saved_char;
            }
            free(temp_line);
            return -1;
        }

        // Restore the original character at comma position
        if (comma != NULL) {
            *comma = saved_char;
            current = comma + 1;
        } else {
            current += token_len;
        }
    }

    // Verify all required fields were parsed successfully
    if (fields_set != (FLAG_CPU | FLAG_MEM | FLAG_DISK | FLAG_NET)) {
        free(temp_line);
        return -1;
    }

    // Cleanup and return success
    free(temp_line);
    return 0;
}

